body.script:
// Proxy registration
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('https://cdn.jsdelivr.net/gh/PeteZah-G/PeteStatic@main/sw.js')
    .then(() => console.log('%c✅ Proxy Ready', 'color:#60a5fa;font-weight:bold'));
}

let tabs = [], current = 0;

function renderTabs() {
  const container = document.getElementById('tabBar');
  container.innerHTML = '';
  tabs.forEach((tab, i) => {
    const el = document.createElement('div');
    el.className = `tab ${i === current ? 'active' : ''}`;
    el.innerHTML = `${tab.title} <span onclick="event.stopImmediatePropagation(); closeTab(${i});" style="margin-left:10px;color:#999;">×</span>`;
    el.onclick = () => switchTab(i);
    container.appendChild(el);
  });
}

function addTab(url) {
  if (!url.startsWith('http')) url = 'https://' + url;
  const title = new URL(url).hostname.replace('www.', '');
  tabs.push({url, title});
  current = tabs.length - 1;
  loadCurrent();
}

function switchTab(i) {
  current = i;
  loadCurrent();
}

function loadCurrent() {
  if (tabs.length === 0) return;
  document.getElementById('mainFrame').src = tabs[current].url;
  renderTabs();
}

function closeTab(i) {
  if (tabs.length <= 1) return;
  tabs.splice(i, 1);
  if (current >= tabs.length) current = tabs.length - 1;
  loadCurrent();
}

function goUrl() {
  const val = document.getElementById('urlInput').value.trim();
  if (val) addTab(val);
}

function customize() {
  const newName = prompt('New platform name?', document.title);
  if (newName) document.title = newName;
}

function panic() {
  document.body.style.display = 'none';
  setTimeout(() => document.body.style.display = 'flex', 1200);
}

let escCount = 0;
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    escCount++;
    if (escCount >= 2) {
      document.body.style.display = 'none';
      setTimeout(() => {
        if (confirm('Return to NexusForge?')) document.body.style.display = 'flex';
      }, 800);
      escCount = 0;
    }
  }
});

// Start
window.onload = () => addTab('https://google.com');
